def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import random
    import pygmo as pg
    from scipy.spatial.distance import cdist

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache = {}

    def compute_hv(indices):
        if not indices:
            return 0.0
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        subset_points = points[list(indices)]
        hv = pg.hypervolume(subset_points)
        result = hv.compute(reference_point)
        hv_cache[key] = result
        return result

    def incremental_contrib(current_set, candidate):
        if candidate in current_set:
            return 0.0
        new_set = frozenset(current_set | {candidate})
        return compute_hv(new_set) - compute_hv(current_set)

    best_set = None
    best_hv = -np.inf

    num_starts = max(3, min(8, n // 50))

    for start in range(num_starts):
        if start == 0:
            current_set = set()
            remaining = list(range(n))
            random.shuffle(remaining)
            candidate_pool = set(remaining[:min(50, n)])

            for _ in range(k):
                best_contrib = -np.inf
                best_cand = None
                for cand in candidate_pool:
                    if cand not in current_set:
                        contrib = incremental_contrib(current_set, cand)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_cand = cand
                if best_cand is not None:
                    current_set.add(best_cand)
                    candidate_pool.remove(best_cand)
                else:
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
        elif start == 1:
            current_set = set(random.sample(range(n), k))
            candidate_pool = set(random.sample(range(n), min(50, n)))
        else:
            if best_set is not None:
                current_set = best_set.copy()
                num_replace = max(1, k // 4)
                replace_idx = random.sample(list(current_set), num_replace)
                for idx in replace_idx:
                    current_set.remove(idx)
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
            else:
                current_set = set(random.sample(range(n), k))
            candidate_pool = set(random.sample(range(n), min(50, n)))

        if len(current_set) > 0:
            selected_points = points[list(current_set)]
            distances = np.min(cdist(points, selected_points), axis=1)
            unselected = set(range(n)) - current_set
            if unselected:
                unselected_list = list(unselected)
                unselected_distances = distances[unselected_list]
                pool_size = min(50, len(unselected))
                top_indices = np.argsort(unselected_distances)[-pool_size:]
                candidate_pool = {unselected_list[i] for i in top_indices}

        max_iter = 30
        for _ in range(max_iter):
            improved = False
            current_hv = compute_hv(current_set)

            contributions = {}
            for idx in current_set:
                contributions[idx] = current_hv - compute_hv(current_set - {idx})

            sorted_points = sorted(contributions.keys(), key=lambda x: contributions[x])
            low_contrib = sorted_points[:min(3, len(sorted_points))]

            for low_idx in low_contrib:
                for cand in candidate_pool:
                    if cand in current_set:
                        continue
                    new_hv = compute_hv((current_set - {low_idx}) | {cand})
                    if new_hv > current_hv + 1e-12:
                        current_set = (current_set - {low_idx}) | {cand}
                        improved = True
                        break
                if improved:
                    break

            if not improved:
                break

        current_hv = compute_hv(current_set)
        for idx in list(current_set):
            best_gain = -np.inf
            best_cand = None
            for cand in range(n):
                if cand in current_set:
                    continue
                new_hv = compute_hv((current_set - {idx}) | {cand})
                gain = new_hv - current_hv
                if gain > best_gain:
                    best_gain = gain
                    best_cand = cand
            if best_gain > 0:
                current_set = (current_set - {idx}) | {best_cand}
                current_hv += best_gain

        final_hv = compute_hv(current_set)
        if final_hv > best_hv:
            best_hv = final_hv
            best_set = current_set.copy()

    if best_set is None:
        indices = random.sample(range(n), k)
        return points[indices]

    selected_indices = list(best_set)
    if len(selected_indices) > k:
        contributions = []
        for idx in selected_indices:
            contributions.append(best_hv - compute_hv(best_set - {idx}))
        top_k_idx = np.argsort(contributions)[-k:]
        selected_indices = [selected_indices[i] for i in top_k_idx]
    elif len(selected_indices) < k:
        remaining = set(range(n)) - best_set
        need = k - len(selected_indices)
        extra = random.sample(list(remaining), min(need, len(remaining)))
        selected_indices.extend(extra)

    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 超体积缓存
    hv_cache = {}

    def compute_hv(indices: Set[int]) -> float:
        """计算索引集合的超体积"""
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices)]
        hv = pg.hypervolume(data)
        result = hv.compute(reference_point)
        hv_cache[key] = result
        return result

    def incremental_contrib(current_set: Set[int], candidate: int) -> float:
        """增量计算候选点对当前集合的超体积贡献"""
        if candidate in current_set:
            return 0.0
        new_set = frozenset(current_set | {candidate})
        return compute_hv(new_set) - compute_hv(current_set)

    # 多起点搜索
    num_starts = max(2, min(5, n // 100))
    best_set = None
    best_hv = -np.inf

    for start in range(num_starts):
        # 初始化当前解
        if start == 0:
            # 贪心初始化
            current_set = set()
            remaining = list(range(n))
            random.shuffle(remaining)
            candidate_pool = set(remaining[:min(2*k, n)])

            for _ in range(k):
                best_cand = None
                best_contrib = -np.inf
                for cand in candidate_pool:
                    if cand not in current_set:
                        contrib = incremental_contrib(current_set, cand)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_cand = cand
                if best_cand is not None:
                    current_set.add(best_cand)
                    candidate_pool.remove(best_cand)
                else:
                    # 从剩余点中随机选择
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
        else:
            # 随机初始化或扰动最优解
            if best_set is not None and start == 1:
                current_set = best_set.copy()
                # 扰动：随机替换部分点
                num_replace = max(1, k // 5)
                replace_idx = random.sample(list(current_set), num_replace)
                for idx in replace_idx:
                    current_set.remove(idx)
                    remaining_set = set(range(n)) - current_set
                    if remaining_set:
                        current_set.add(random.choice(list(remaining_set)))
            else:
                current_set = set(random.sample(range(n), k))
            candidate_pool = set(random.sample(range(n), min(2*k, n)))

        # 局部搜索：交换低贡献点
        max_iter = 50
        for _ in range(max_iter):
            improved = False
            current_hv = compute_hv(current_set)

            # 计算当前集合中每个点的贡献
            contributions = {}
            for idx in current_set:
                temp_set = current_set - {idx}
                contributions[idx] = current_hv - compute_hv(temp_set)

            # 选择贡献最低的点
            low_contrib = sorted(contributions.keys(), key=lambda x: contributions[x])[:min(3, k)]

            # 尝试替换低贡献点
            for low_idx in low_contrib:
                for cand in candidate_pool:
                    if cand in current_set:
                        continue
                    # 增量评估
                    new_set = (current_set - {low_idx}) | {cand}
                    new_hv = compute_hv(new_set)
                    if new_hv > current_hv + 1e-12:
                        current_set = new_set
                        improved = True
                        break
                if improved:
                    break

            if not improved:
                break

        # 最终确定性单点替换扫描
        current_hv = compute_hv(current_set)
        for idx in list(current_set):
            best_gain = -np.inf
            best_cand = None
            for cand in candidate_pool:
                if cand in current_set:
                    continue
                new_set = (current_set - {idx}) | {cand}
                new_hv = compute_hv(new_set)
                gain = new_hv - current_hv
                if gain > best_gain:
                    best_gain = gain
                    best_cand = cand
            if best_gain > 0:
                current_set = (current_set - {idx}) | {best_cand}
                current_hv += best_gain

        # 更新最优解
        final_hv = compute_hv(current_set)
        if final_hv > best_hv:
            best_hv = final_hv
            best_set = current_set.copy()

    # 确保返回恰好k个点
    if best_set is None:
        indices = random.sample(range(n), k)
        return points[indices]

    selected_indices = list(best_set)
    if len(selected_indices) > k:
        # 保留贡献最大的k个点
        contributions = []
        for idx in selected_indices:
            temp_set = best_set - {idx}
            contributions.append(best_hv - compute_hv(temp_set))
        top_k_idx = np.argsort(contributions)[-k:]
        selected_indices = [selected_indices[i] for i in top_k_idx]
    elif len(selected_indices) < k:
        # 补充随机点
        remaining = set(range(n)) - best_set
        need = k - len(selected_indices)
        extra = random.sample(list(remaining), min(need, len(remaining)))
        selected_indices.extend(extra)

    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # 超体积缓存
    hv_cache = {}

    def compute_hv(indices):
        if not indices:
            return 0.0
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        subset_points = points[list(indices)]
        hv = pg.hypervolume(subset_points)
        result = hv.compute(reference_point)
        hv_cache[key] = result
        return result

    best_set = None
    best_hv = -np.inf

    # 多起点搜索（2种初始化）
    for start in range(2):
        if start == 0:
            # 贪心初始化
            current_set = set()
            for _ in range(k):
                best_inc = -np.inf
                best_idx = -1
                for idx in range(n):
                    if idx in current_set:
                        continue
                    inc = compute_hv(current_set | {idx}) - compute_hv(current_set)
                    if inc > best_inc:
                        best_inc = inc
                        best_idx = idx
                if best_idx >= 0:
                    current_set.add(best_idx)
        else:
            # 随机初始化
            current_set = set(random.sample(range(n), k))

        # 构建距离引导的候选池
        candidate_pool = set()
        if len(current_set) > 0:
            selected_points = points[list(current_set)]
            all_points = points
            # 计算每个未选点到最近选中点的距离
            distances = np.min(cdist(all_points, selected_points), axis=1)
            # 选择距离最远的点作为候选（促进多样性）
            unselected = set(range(n)) - current_set
            if unselected:
                unselected_list = list(unselected)
                unselected_distances = distances[unselected_list]
                # 取距离最大的前 min(2*k, len(unselected)) 个点
                pool_size = min(2 * k, len(unselected))
                top_indices = np.argsort(unselected_distances)[-pool_size:]
                candidate_pool = {unselected_list[i] for i in top_indices}
        else:
            candidate_pool = set(random.sample(range(n), min(2*k, n)))

        # 局部搜索：交换低贡献点
        max_iter = 50
        for iteration in range(max_iter):
            improved = False
            current_hv = compute_hv(current_set)

            # 计算贡献
            contributions = {}
            for idx in current_set:
                contributions[idx] = current_hv - compute_hv(current_set - {idx})

            # 识别最低贡献点
            sorted_points = sorted(contributions.keys(), key=lambda x: contributions[x])
            low_contrib = sorted_points[:min(2, len(sorted_points))]

            # 尝试交换
            for low_idx in low_contrib:
                for cand in candidate_pool:
                    if cand in current_set:
                        continue
                    new_hv = compute_hv((current_set - {low_idx}) | {cand})
                    if new_hv > current_hv + 1e-12:
                        current_set = (current_set - {low_idx}) | {cand}
                        improved = True
                        break
                if improved:
                    break

            if not improved:
                break

        # 最终确定性单点替换
        current_hv = compute_hv(current_set)
        for idx in list(current_set):
            best_gain = -np.inf
            best_cand = None
            # 使用所有未选点作为候选
            for cand in range(n):
                if cand in current_set:
                    continue
                new_hv = compute_hv((current_set - {idx}) | {cand})
                gain = new_hv - current_hv
                if gain > best_gain:
                    best_gain = gain
                    best_cand = cand
            if best_gain > 0:
                current_set = (current_set - {idx}) | {best_cand}
                current_hv += best_gain

        # 更新最佳解
        final_hv = compute_hv(current_set)
        if final_hv > best_hv:
            best_hv = final_hv
            best_set = current_set.copy()

    # 确保返回恰好k个点
    if not best_set:
        indices = random.sample(range(n), k)
        return points[indices]

    selected_indices = list(best_set)
    if len(selected_indices) > k:
        # 选择贡献最大的k个点
        contributions = []
        for idx in selected_indices:
            contributions.append(best_hv - compute_hv(best_set - {idx}))
        top_k_idx = np.argsort(contributions)[-k:]
        selected_indices = [selected_indices[i] for i in top_k_idx]
    elif len(selected_indices) < k:
        # 补充随机点
        remaining = set(range(n)) - best_set
        need = k - len(selected_indices)
        extra = random.sample(list(remaining), min(need, len(remaining)))
        selected_indices.extend(extra)

    return points[selected_indices]
